<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\CombatStateStatus;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;use PHPUnit\Framework\TestCase;class CombatStateTest extends TestCase{private function f($id){return new CombatantStats($id,$id,10,10,1,0,0,0,0,1,1,0);}public function test_round_and_duplicate_identifiers(){$s=new CombatState($this->f('c'),$this->f('m'),10,10,1,'c','c',CombatStateStatus::IN_PROGRESS);$this->assertSame(1,$s->roundNumber());$this->expectException(\InvalidArgumentException::class);new CombatState($this->f('x'),$this->f('x'),10,10,1,'x','x',CombatStateStatus::IN_PROGRESS);}public function test_terminal_state_coherence(){new CombatState($this->f('c'),$this->f('m'),10,0,1,'c',null,CombatResultStatus::CHARACTER_VICTORY);$this->expectException(\InvalidArgumentException::class);new CombatState($this->f('c'),$this->f('m'),10,10,1,'c',null,CombatResultStatus::CHARACTER_VICTORY);}}
